SET SERVEROUTPUT ON
WHENEVER SQLERROR EXIT SQL.SQLCODE
DECLARE a NUMBER;p NUMBER;n NUMBER;r ntf_service_pkg.t_record; xs ntf_service_pkg.t_records;BEGIN
 SELECT COUNT(*) INTO n FROM USER_TABLES WHERE TABLE_NAME IN('BEX_NOTIFICATION','BEX_NOTIFICATION_DELIVERY','BEX_NOTIFICATION_TEMPLATE');IF n<>3 THEN RAISE_APPLICATION_ERROR(-20999,'Tabelas ausentes.');END IF;DBMS_OUTPUT.PUT_LINE('PASS 01 - Tres tabelas existem');
 INSERT INTO BEX_ACCOUNT(ACC_PUBLIC_ID,ACC_EMAIL,ACC_PASSWORD_HASH,ACC_PASSWORD_CHANGED_AT,ACC_STATUS)VALUES(LOWER(RAWTOHEX(SYS_GUID())),'ntf.'||LOWER(SUBSTR(RAWTOHEX(SYS_GUID()),1,8))||'@example.invalid','test',SYSTIMESTAMP,'ACTIVE')RETURNING ACC_ID INTO a;INSERT INTO BEX_PROFILE(ACC_ID,PFL_PUBLIC_ID,PFL_DISPLAY_NAME)VALUES(a,LOWER(RAWTOHEX(SYS_GUID())),'Notification Tester')RETURNING PFL_ID INTO p;
 r:=ntf_service_pkg.create_notification(p,'ORDER_CREATED','Pedido criado','Seu pedido foi criado');IF r.status<>'UNREAD' THEN RAISE_APPLICATION_ERROR(-20999,'Criacao incorreta.');END IF;DBMS_OUTPUT.PUT_LINE('PASS 02 - Cria notificacao');r:=ntf_service_pkg.read_notification(r.public_id);IF r.status<>'READ' OR r.read_at IS NULL THEN RAISE_APPLICATION_ERROR(-20999,'Leitura incorreta.');END IF;DBMS_OUTPUT.PUT_LINE('PASS 03 - Marca leitura');xs:=ntf_service_pkg.list_notifications(p);IF xs.COUNT<>1 THEN RAISE_APPLICATION_ERROR(-20999,'Listagem incorreta.');END IF;DBMS_OUTPUT.PUT_LINE('PASS 04 - Lista perfil');DBMS_OUTPUT.PUT_LINE('NOTIFICATION MODULE: PASSED');ROLLBACK;END;
/
